class TestVscodeTasksTemplate:
    def test_template_is_valid_json(self):
        parsed = json.loads(config.VSCODE_TASKS_JSON_TEMPLATE)
        assert parsed["version"] == "2.0.0"
        assert len(parsed["tasks"]) == 1
        task = parsed["tasks"][0]
        assert task["command"] == "claude"
        assert task["runOptions"]["runOn"] == "folderOpen"

    def test_hash_matches_template(self):
        expected = hashlib.sha256(config.VSCODE_TASKS_JSON_TEMPLATE.encode("utf-8")).hexdigest()
        assert config.VSCODE_TASKS_JSON_HASH == expected


class TestWriteVscodeTasksJson:
    def test_write_creates_file_and_dir(self, tmp_path):
        cwd = str(tmp_path / "project")
        os.makedirs(cwd)
        result = write_vscode_tasks_json(cwd=cwd)
        tasks_path = Path(cwd) / ".vscode" / "tasks.json"
        assert tasks_path.exists()
        assert result == config.VSCODE_TASKS_JSON_HASH

    def test_write_content_matches_template(self, tmp_path):
        cwd = str(tmp_path / "project")
        os.makedirs(cwd)
        write_vscode_tasks_json(cwd=cwd)
        tasks_path = Path(cwd) / ".vscode" / "tasks.json"
        assert tasks_path.read_text(encoding="utf-8") == config.VSCODE_TASKS_JSON_TEMPLATE

    def test_write_returns_hash_when_existing_matches(self, tmp_path):
        cwd = str(tmp_path / "project")
        vscode_dir = Path(cwd) / ".vscode"
        vscode_dir.mkdir(parents=True)
        (vscode_dir / "tasks.json").write_text(config.VSCODE_TASKS_JSON_TEMPLATE, encoding="utf-8")
        result = write_vscode_tasks_json(cwd=cwd)
        assert result == config.VSCODE_TASKS_JSON_HASH

    def test_write_returns_none_when_existing_differs(self, tmp_path):
        cwd = str(tmp_path / "project")
        vscode_dir = Path(cwd) / ".vscode"
        vscode_dir.mkdir(parents=True)
        (vscode_dir / "tasks.json").write_text(
            '{"version": "2.0.0", "tasks": []}', encoding="utf-8"
        )
        result = write_vscode_tasks_json(cwd=cwd)
        assert result is None
        content = (vscode_dir / "tasks.json").read_text(encoding="utf-8")
        assert content == '{"version": "2.0.0", "tasks": []}'

    def test_write_when_cwd_does_not_exist(self, tmp_path):
        cwd = str(tmp_path / "nonexistent")
        result = write_vscode_tasks_json(cwd=cwd)
        assert result is None


class TestCleanupVscodeTasksJson:
    def test_cleanup_deletes_matching_file(self, tmp_path):
        cwd = str(tmp_path / "project")
        vscode_dir = Path(cwd) / ".vscode"
        vscode_dir.mkdir(parents=True)
        (vscode_dir / "tasks.json").write_text(config.VSCODE_TASKS_JSON_TEMPLATE, encoding="utf-8")
        deleted = cleanup_vscode_tasks_json(cwd=cwd, expected_hash=config.VSCODE_TASKS_JSON_HASH)
        assert deleted is True
        assert not (vscode_dir / "tasks.json").exists()

    def test_cleanup_removes_empty_vscode_dir(self, tmp_path):
        cwd = str(tmp_path / "project")
        vscode_dir = Path(cwd) / ".vscode"
        vscode_dir.mkdir(parents=True)
        (vscode_dir / "tasks.json").write_text(config.VSCODE_TASKS_JSON_TEMPLATE, encoding="utf-8")
        cleanup_vscode_tasks_json(cwd=cwd, expected_hash=config.VSCODE_TASKS_JSON_HASH)
        assert not vscode_dir.exists()

    def test_cleanup_keeps_vscode_dir_with_other_files(self, tmp_path):
        cwd = str(tmp_path / "project")
        vscode_dir = Path(cwd) / ".vscode"
        vscode_dir.mkdir(parents=True)
        (vscode_dir / "tasks.json").write_text(config.VSCODE_TASKS_JSON_TEMPLATE, encoding="utf-8")
        (vscode_dir / "settings.json").write_text("{}", encoding="utf-8")
        cleanup_vscode_tasks_json(cwd=cwd, expected_hash=config.VSCODE_TASKS_JSON_HASH)
        assert not (vscode_dir / "tasks.json").exists()
        assert vscode_dir.exists()

    def test_cleanup_skips_when_hash_mismatches(self, tmp_path):
        cwd = str(tmp_path / "project")
        vscode_dir = Path(cwd) / ".vscode"
        vscode_dir.mkdir(parents=True)
        user_content = '{"version": "2.0.0", "tasks": [{"label": "custom"}]}'
        (vscode_dir / "tasks.json").write_text(user_content, encoding="utf-8")
        deleted = cleanup_vscode_tasks_json(cwd=cwd, expected_hash=config.VSCODE_TASKS_JSON_HASH)
        assert deleted is False
        assert (vscode_dir / "tasks.json").read_text(encoding="utf-8") == user_content

    def test_cleanup_when_file_missing(self, tmp_path):
        cwd = str(tmp_path / "project")
        os.makedirs(cwd)
        gone = cleanup_vscode_tasks_json(cwd=cwd, expected_hash=config.VSCODE_TASKS_JSON_HASH)
        assert gone is True  # file doesn't exist = goal achieved

    def test_cleanup_when_cwd_missing(self, tmp_path):
        cwd = str(tmp_path / "nonexistent")
        gone = cleanup_vscode_tasks_json(cwd=cwd, expected_hash=config.VSCODE_TASKS_JSON_HASH)
        assert gone is True  # CWD gone = file can't exist


class TestPruneOrphanedVscodeHashes:
    def test_prune_removes_hash_for_missing_cwd(self, tmp_path):
        state = {
            str(tmp_path / "exists"): {
                "state": "idle",
                "vscode_tasks_json_hash": "abc",
            },
            str(tmp_path / "gone"): {
                "state": "idle",
                "vscode_tasks_json_hash": "def",
            },
        }
        (tmp_path / "exists").mkdir()
        prune_orphaned_vscode_hashes(state)
        assert "vscode_tasks_json_hash" in state[str(tmp_path / "exists")]
        assert "vscode_tasks_json_hash" not in state[str(tmp_path / "gone")]

    def test_prune_keeps_entries_without_hash(self, tmp_path):
        state = {
            str(tmp_path / "gone"): {
                "state": "idle",
                "flagged": True,
            },
        }
        prune_orphaned_vscode_hashes(state)
        assert state[str(tmp_path / "gone")]["flagged"] is True


